import os, sys, json, argparse, math
from cogniplan_env import ExplorationEnv

class Planner:
    def __init__(self, alpha=1.0, alpha_slope=2.0, vp=0.5, nuw=0.8):
        self.alpha = alpha
        self.alpha_slope = alpha_slope
        self.vp = vp
        self.nuw = nuw
        self.visited = set()

    def reset(self):
        self.visited = set()

    def _key(self, c):
        return (round(c[0], 1), round(c[1], 1))

    def select(self, obs):
        nodes = obs['nodes']
        neighbors = obs['neighbors']
        rp = obs['robot_pos']
        er = obs['explored_rate']
        self.visited.add(self._key(rp))
        if not neighbors:
            return None

        util = {}
        nn_map = {}
        for n in nodes:
            k = self._key(n['coords'])
            util[k] = float(n['utility'])
            nn_map[k] = [self._key(x) for x in n.get('neighbors', [])]

        ea = self.alpha + self.alpha_slope * er

        def score_nbs(vp_val):
            best_s, best_t = -1e18, None
            for nb in neighbors:
                nk = self._key(nb)
                dx, dy = nb[0] - rp[0], nb[1] - rp[1]
                d = math.sqrt(dx*dx + dy*dy)
                if d < 0.01:
                    d = 0.01
                u = util.get(nk, 0)
                for nnk in nn_map.get(nk, []):
                    u += self.nuw * util.get(nnk, 0)
                if nk in self.visited:
                    u *= (1.0 - vp_val)
                if u <= 0:
                    continue
                s = u / (d ** ea)
                if s > best_s:
                    best_s, best_t = s, nb
            return best_t

        best = score_nbs(self.vp)
        if best is None:
            best = score_nbs(0.0)

        if best is None:
            best_u, best_c = 0, None
            for n in nodes:
                k = self._key(n['coords'])
                u = float(n['utility'])
                if k not in self.visited and u > best_u:
                    best_u, best_c = u, n['coords']
            if best_c is not None:
                best_d = float('inf')
                for nb in neighbors:
                    dx, dy = nb[0] - best_c[0], nb[1] - best_c[1]
                    d2 = dx*dx + dy*dy
                    if d2 < best_d:
                        best_d, best = d2, nb

        if best is None:
            for nb in neighbors:
                if self._key(nb) not in self.visited:
                    best = nb
                    break
        if best is None and neighbors:
            best = neighbors[0]
        return best

def run_episode(env, planner):
    obs = env.reset()
    planner.reset()
    for _ in range(128):
        target = planner.select(obs)
        if target is None:
            break
        obs, info = env.step(target)
        if info.get('done', False):
            break
    return env.get_metrics()

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True)
    parser.add_argument('--checkpoint', required=True)
    parser.add_argument('--output', required=True)
    args = parser.parse_args()

    cfg_path = os.path.join(args.checkpoint, 'config.json')
    cfg = {}
    if os.path.exists(cfg_path):
        with open(cfg_path) as f:
            cfg = json.load(f)

    planner = Planner(
        alpha=cfg.get('alpha', 1.0),
        alpha_slope=cfg.get('alpha_slope', 2.0),
        vp=cfg.get('visited_penalty', 0.5),
        nuw=cfg.get('neighbor_util_weight', 0.8),
    )

    maps_dir = os.path.join(args.data_path, 'maps_eval')
    episodes = []
    for et in ['room', 'tunnel', 'outdoor']:
        td = os.path.join(maps_dir, et)
        if not os.path.isdir(td):
            continue
        for fn in sorted(os.listdir(td)):
            if fn.endswith('.png'):
                episodes.append({'map_path': os.path.join(et, fn), 'env_type': et, 'full_path': os.path.join(td, fn)})

    per_episode, per_type = [], {}
    for ep in episodes:
        env = ExplorationEnv(map_path=ep['full_path'])
        m = run_episode(env, planner)
        r = {'map_path': ep['map_path'], 'env_type': ep['env_type'], 'success': 1 if m['success'] else 0, 'travel_distance': m['travel_distance'], 'explored_rate': m['explored_rate']}
        per_episode.append(r)
        per_type.setdefault(ep['env_type'], []).append(r)

    total = len(per_episode)
    er = sum(r['explored_rate'] for r in per_episode) / total if total else 0
    sr = sum(r['success'] for r in per_episode) / total if total else 0
    sd = [r['travel_distance'] for r in per_episode if r['success'] == 1]
    td_val = sum(sd) / len(sd) if sd else 0.0

    pts = {}
    for t, rs in per_type.items():
        n = len(rs)
        sc = sum(r['success'] for r in rs)
        pts[t] = {'explored_rate': sum(r['explored_rate'] for r in rs) / n if n else 0, 'travel_distance': sum(r['travel_distance'] for r in rs if r['success'] == 1) / max(1, sc), 'success_rate': sc / n if n else 0}

    out = {'explored_rate': er, 'travel_distance': td_val, 'success_rate': sr, 'per_episode': per_episode, 'per_type': pts, 'total_episodes': total}
    with open(args.output, 'w') as f:
        json.dump(out, f, indent=2)
    print(f'Done: {total} ep, explored={er:.4f}, success={sr:.4f}')

if __name__ == '__main__':
    main()
